1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	interface Item {
11	  type: string;
12	}
13	
14	interface QuoteStep {
15	  items: Item[];
16	}
17	
18	// Premiums are rounded UP, in MHPCO's favor. The toFixed(6) collapses
19	// floating-point artifacts (e.g. 197.49999999) so we don't round a value
20	// that is only spuriously above a whole number.
21	const roundUpInMHPCOsFavor = (amount: number): number =>
22	  Math.ceil(Number(amount.toFixed(6)));
23	
24	export const quote = (
25	  customer: unknown,
26	  step: QuoteStep,
27	  quoteIndex: number,
28	): number => {
29	  let basePremium = 0;
30	  for (const item of step.items) {
31	    basePremium += BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
32	  }
33	  const withFirstInsurance = basePremium * (1 + FIRST_INSURANCE_SURCHARGE);
34	  const total = withFirstInsurance + PROCESSING_FEE;
35	  return roundUpInMHPCOsFavor(total);
36	};
37	
38	export const claim = (...args: unknown[]): unknown => {
39	  return undefined; // Intentionally not implemented
40	};
